class Solution:
    def isCousins(self, root, x, y):
        from collections import deque
        # BFS level by level, recording the parent of x and y when found
        q = deque([(root, None)])
        while q:
            found_x = found_y = None
            for _ in range(len(q)):
                node, parent = q.popleft()
                if node.val == x:
                    found_x = parent
                if node.val == y:
                    found_y = parent
                if node.left is not None:
                    q.append((node.left, node.val))
                if node.right is not None:
                    q.append((node.right, node.val))
            if found_x is not None and found_y is not None:
                return found_x != found_y
            if found_x is not None or found_y is not None:
                return False
        return False

