class Solution:
    def isCousins(self, root, x, y):
        info = {}
        def dfs(node, depth, parent):
            if node is None:
                return
            if node.val == x or node.val == y:
                info[node.val] = (depth, parent)
            dfs(node.left, depth + 1, node.val)
            dfs(node.right, depth + 1, node.val)
        dfs(root, 0, None)
        dx, px = info[x]
        dy, py = info[y]
        return dx == dy and px != py

