var isCousins = function(root, x, y) {
    const info = {};
    const dfs = (node, depth, parent) => {
        if (node === null) return;
        if (node.val === x || node.val === y) info[node.val] = [depth, parent];
        dfs(node.left, depth + 1, node.val);
        dfs(node.right, depth + 1, node.val);
    };
    dfs(root, 0, null);
    const [dx, px] = info[x];
    const [dy, py] = info[y];
    return dx === dy && px !== py;
};
